-- ============================================================================
-- Quiz Seed: Numbers — Part 2 (Chapters 11–20)
-- 3 difficulties × 10 chapters = 160 total questions
--   kids:   3 per chapter  = 30
--   teens:  5 per chapter  = 50
--   adults: 8 per chapter  = 80
-- ============================================================================

-- ═══ Numbers Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 11, 'kids', 1, 'What did the people do that made the LORD angry and send fire among them?', 'They complained and murmured against Him', 'They refused to pray', 'They forgot to bring offerings', 'They ran away from the camp', 'a', 'Numbers 11:1 — "And when the people complained, it displeased the LORD: and the LORD heard it; and his anger was kindled; and the fire of the LORD burnt among them."'),
('Numbers', 11, 'kids', 2, 'What food did God send to feed the complaining people in the wilderness?', 'Quail', 'Bread and honey', 'Fish from the sea', 'Figs and dates', 'a', 'Numbers 11:31 — "And there went forth a wind from the LORD, and brought quails from the sea, and let them fall by the camp."'),
('Numbers', 11, 'kids', 3, 'How many elders did Moses choose to help him lead the people?', 'Seventy elders of Israel', 'Twelve leaders', 'Forty helpers', 'One hundred men', 'a', 'Numbers 11:24 — "And Moses went out, and told the people the words of the LORD, and gathered the seventy men of the elders of the people."'),
-- Teens
('Numbers', 11, 'teens', 1, 'What did the people say they missed eating in Egypt when they complained about the manna?', 'Fish, cucumbers, melons, leeks, onions, and garlic', 'Bread and wine', 'Lamb and barley', 'Grapes and figs', 'a', 'Numbers 11:5 — "We remember the fish, which we did eat in Egypt freely; the cucumbers, and the melons, and the leeks, and the onions, and the garlick."'),
('Numbers', 11, 'teens', 2, 'What happened to two men named Eldad and Medad who did not go to the tabernacle with the other elders?', 'The Spirit rested upon them and they prophesied in the camp', 'They were punished for staying back', 'They left Israel and went to Egypt', 'They built their own altar', 'a', 'Numbers 11:26-27 — "But there remained two of the men in the camp, the name of the one was Eldad, and the name of the other Medad: and the spirit rested upon them... and they prophesied in the camp."'),
('Numbers', 11, 'teens', 3, 'What did Joshua ask Moses to do about Eldad and Medad prophesying?', 'Forbid them', 'Reward them with silver', 'Make them priests', 'Send them to lead the army', 'a', 'Numbers 11:28 — "And Joshua the son of Nun, the servant of Moses, one of his young men, answered and said, My lord Moses, forbid them."'),
('Numbers', 11, 'teens', 4, 'Why did Moses say he wished all of God''s people were prophets?', 'He wished the LORD would put His spirit upon all of them', 'He wanted to rest from teaching', 'He was tired of being the only leader', 'He wanted to return to Egypt', 'a', 'Numbers 11:29 — "And Moses said unto him, Enviest thou for my sake? would God that all the LORD''s people were prophets, and that the LORD would put his spirit upon them!"'),
('Numbers', 11, 'teens', 5, 'What happened to the people who greedily ate the quail before they had fully chewed it?', 'The LORD smote them with a very great plague while the flesh was yet between their teeth', 'They became very strong', 'They fell asleep for three days', 'Nothing happened to them', 'a', 'Numbers 11:33 — "And while the flesh was yet between their teeth, ere it was chewed, the wrath of the LORD was kindled against the people, and the LORD smote the people with a very great plague."'),
-- Adults
('Numbers', 11, 'adults', 1, 'What is the Hebrew name given to the burial place in Numbers 11, and what does it mean?', 'Kibroth-hattaavah, meaning "graves of craving" or "graves of lust" — so named because Israel was buried there for their inordinate craving for flesh', 'Taberah, meaning "burning"', 'Meribah, meaning "striving"', 'Massah, meaning "testing"', 'a', 'Numbers 11:34 — "And he called the name of that place Kibroth-hattaavah: because there they buried the people that lusted." The name memorializes the deadly consequence of sinful craving.'),
('Numbers', 11, 'adults', 2, 'What does the description of manna in Numbers 11:7-8 reveal about the nature of Israel''s ingratitude?', 'Manna was a miraculous, versatile food — white as coriander seed, tasting like fresh oil — meaning their complaint was against a genuine divine provision, not mere inadequacy', 'Manna was unpleasant and hard to eat', 'The people had never eaten manna before', 'Manna caused illness', 'a', 'Numbers 11:7-8 — "And the manna was as coriander seed, and the colour thereof as the colour of bdellium... and the taste of it was as the taste of fresh oil." Their complaint reveals the sin of ingratitude for miraculous provision.'),
('Numbers', 11, 'adults', 3, 'How does Moses'' complaint to God in Numbers 11:11-15 reflect both his humanity and his unique intercessory role?', 'Moses honestly voices his despair and inability to bear the nation alone — even asking for death — yet remains in dialogue with God, modeling transparent intercession rather than silent resignation', 'Moses was sinning by complaining', 'Moses asked to return to Egypt', 'Moses expressed perfect contentment', 'a', 'Numbers 11:14-15 — "I am not able to bear all this people alone, because it is too heavy for me. And if thou deal thus with me, kill me, I pray thee, out of hand." Moses'' raw honesty before God is a mark of intimate relationship, not rebellion.'),
('Numbers', 11, 'adults', 4, 'How does the seventy elders episode in Numbers 11 foreshadow New Testament Pentecost themes?', 'The Spirit is distributed from Moses to seventy others, expanding prophetic ministry beyond one leader — anticipating Joel 2:28 and Acts 2 where the Spirit is poured out on all flesh', 'The episode is unrelated to later Scripture', 'The Spirit was divided and weakened', 'Only priests could receive the Spirit', 'a', 'Numbers 11:25 — "The LORD came down in a cloud, and spake unto him, and took of the spirit that was upon him, and gave it unto the seventy elders." Moses'' wish (v.29) is fulfilled at Pentecost (Acts 2:17).'),
('Numbers', 11, 'adults', 5, 'What theological principle does Numbers 11:4 establish about "the mixed multitude" who traveled with Israel?', 'The mixed multitude (Hebrew: asafsuf — "rabble") instigated the lusting, showing that compromised fellowship and inclusion of the ungodly within the covenant community breeds spiritual corruption', 'The mixed multitude strengthened Israel', 'The mixed multitude were model worshippers', 'Their presence was irrelevant to the narrative', 'a', 'Numbers 11:4 — "And the mixt multitude that was among them fell a lusting: and the children of Israel also wept again." The rabble''s influence dragged the whole community into sin.'),
('Numbers', 11, 'adults', 6, 'How does the LORD''s response to Israel''s meat craving in Numbers 11 demonstrate both divine provision and divine judgment simultaneously?', 'God grants exactly what they asked — enough quail for an entire month — but also sends a plague, showing that God sometimes gives sinful desires as judgment (cf. Psalm 106:15)', 'God refused to provide and only punished', 'God provided and no one was harmed', 'God delayed answering for forty days', 'a', 'Numbers 11:20,33 — God promises quail "until it come out at your nostrils, and it be loathsome unto you" (v.20) and smites the people while eating it (v.33). Psalm 106:15 says God "sent leanness into their soul."'),
('Numbers', 11, 'adults', 7, 'What does the distance measurement of "two cubits" of quail covering the ground (Numbers 11:31) convey theologically?', 'The abundance was supernaturally excessive — two cubits deep for a day''s journey in every direction — emphasizing that the judgment came through surfeit, not shortage, exposing the sin of insatiable craving', 'It shows the quail were small birds', 'It was a normal seasonal migration', 'It describes the height of the camp walls', 'a', 'Numbers 11:31 — "And there went forth a wind from the LORD, and brought quails... as it were two cubits high upon the face of the earth." The overwhelming abundance itself became the instrument of judgment.'),
('Numbers', 11, 'adults', 8, 'How does Moses'' statement in Numbers 11:22 — "Shall all the fish of the sea be gathered together for them, to suffice them?" — reveal a momentary lapse of faith?', 'Moses focuses on the natural impossibility rather than trusting in the God who had already parted the sea and rained bread from heaven — prompting God''s gentle rebuke "is the LORD''s hand waxed short?"', 'Moses was being appropriately cautious', 'Moses was quoting the people''s words', 'Moses had no doubt about God''s power', 'a', 'Numbers 11:23 — "And the LORD said unto Moses, Is the LORD''s hand waxed short? thou shalt see now whether my word shall come to pass unto thee or not." God rebukes Moses'' momentary unbelief.');

-- ═══ Numbers Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 12, 'kids', 1, 'What sickness did Miriam get after she spoke against Moses?', 'Leprosy — her skin became white as snow', 'A fever', 'Blindness', 'A broken arm', 'a', 'Numbers 12:10 — "And the cloud departed from off the tabernacle; and, behold, Miriam became leprous, white as snow."'),
('Numbers', 12, 'kids', 2, 'How long did Miriam have to stay outside the camp?', 'Seven days', 'One day', 'Forty days', 'Three days', 'a', 'Numbers 12:14 — "And the LORD said unto Moses, Let her be shut out from the camp seven days, and after that let her be received in again."'),
('Numbers', 12, 'kids', 3, 'What did Moses do for Miriam when she was struck with leprosy?', 'He prayed to God to heal her', 'He sent her back to Egypt', 'He gave her medicine', 'He built her a special tent', 'a', 'Numbers 12:13 — "And Moses cried unto the LORD, saying, Heal her now, O God, I beseech thee."'),
-- Teens
('Numbers', 12, 'teens', 1, 'What was Miriam and Aaron''s stated reason for speaking against Moses?', 'Because of the Ethiopian woman Moses had married', 'Because Moses kept all the best food', 'Because Moses would not share his authority', 'Because Moses ignored their advice', 'a', 'Numbers 12:1 — "And Miriam and Aaron spake against Moses because of the Ethiopian woman whom he had married: for he had married an Ethiopian woman."'),
('Numbers', 12, 'teens', 2, 'What greater issue did Miriam and Aaron raise beyond Moses'' marriage?', 'They questioned whether God had spoken only by Moses, asking "Hath he not spoken also by us?"', 'They asked why Moses received better food', 'They demanded Moses step down as leader', 'They asked to return to Egypt', 'a', 'Numbers 12:2 — "And they said, Hath the LORD indeed spoken only by Moses? hath he not spoken also by us? And the LORD heard it."'),
('Numbers', 12, 'teens', 3, 'How did the LORD describe Moses in Numbers 12 regarding his meekness?', 'Moses was very meek, above all the men which were upon the face of the earth', 'Moses was the wisest man alive', 'Moses was the strongest warrior in Israel', 'Moses was the most wealthy leader', 'a', 'Numbers 12:3 — "Now the man Moses was very meek, above all the men which were upon the face of the earth."'),
('Numbers', 12, 'teens', 4, 'How did God say He spoke to the prophets compared to how He spoke to Moses?', 'To prophets He spoke in visions and dreams; to Moses He spoke mouth to mouth, plainly, and Moses saw the similitude of the LORD', 'To Moses He spoke in riddles', 'God spoke to all prophets the same way', 'Moses only received dreams', 'a', 'Numbers 12:6-8 — "I the LORD will make myself known unto him in a vision, and will speak unto him in a dream. My servant Moses is not so, who is faithful in all mine house. With him will I speak mouth to mouth, even apparently."'),
('Numbers', 12, 'teens', 5, 'Why did Miriam receive the leprosy and not Aaron?', 'Scripture indicates Miriam was the instigator — the verb "spake" in Hebrew is in the feminine form — and Aaron received a verbal rebuke while Miriam bore the physical judgment', 'Aaron was not present', 'Aaron repented immediately', 'God chose randomly', 'a', 'Numbers 12:10 — "And the cloud departed from off the tabernacle; and, behold, Miriam became leprous." Grammatically in Hebrew, Miriam''s name comes first (v.1) and the verb is feminine singular, indicating she was the primary instigator.'),
-- Adults
('Numbers', 12, 'adults', 1, 'Who is the "Ethiopian woman" (Hebrew: Kushith) Moses married, and what are the two main scholarly interpretations?', 'Either Zipporah the Midianite (Midian being associated with Cushan in Habakkuk 3:7), or a second wife Moses took after Zipporah''s death — the text leaves the identity deliberately ambiguous', 'She was definitely a pagan Canaanite', 'She was an Egyptian from Pharaoh''s court', 'She was one of the daughters of Zelophehad', 'a', 'Numbers 12:1 — "Miriam and Aaron spake against Moses because of the Ethiopian woman whom he had married." Habakkuk 3:7 parallels Cushan with Midian, suggesting Zipporah; others argue for a second marriage. The Bible does not condemn the marriage.'),
('Numbers', 12, 'adults', 2, 'What does God''s anger in Numbers 12:9 and the cloud departing teach about the relationship between attacking God''s servant and divine presence?', 'Attacking God''s appointed servant is tantamount to challenging God Himself — the departure of the cloud (Shekinah) signals that such rebellion separates the rebels from divine presence', 'God was indifferent to the complaint', 'The cloud left for an unrelated reason', 'God only punished Miriam for personal sins', 'a', 'Numbers 12:9-10 — "And the anger of the LORD was kindled against them; and he departed. And the cloud departed from off the tabernacle." The sequence is direct: rebellion against Moses → God''s anger → withdrawal of presence.'),
('Numbers', 12, 'adults', 3, 'What is the typological significance of Moses interceding for the very one who sinned against him?', 'Moses foreshadows Christ''s intercessory ministry — the one wronged becomes the mediator for the one who wronged him, pointing to Christ''s intercession for those who crucified Him', 'It shows Moses had no sense of justice', 'Intercession for enemies was common in Israel', 'Moses was required by law to intercede', 'a', 'Numbers 12:13 — "And Moses cried unto the LORD, saying, Heal her now, O God, I beseech thee." Moses'' intercession for Miriam who had attacked him prefigures Christ''s "Father, forgive them" (Luke 23:34).'),
('Numbers', 12, 'adults', 4, 'How does God''s description of Moses as "faithful in all mine house" (Numbers 12:7) appear in the New Testament and what does it mean?', 'Hebrews 3:2-5 quotes this phrase, comparing Moses'' faithfulness as a servant in God''s house to Christ''s faithfulness as a Son over His house — Moses is the type, Christ the antitype', 'The phrase is not used in the New Testament', 'It refers only to Moses'' household management', 'Hebrews quotes it to criticize Moses', 'a', 'Numbers 12:7 — "My servant Moses is not so, who is faithful in all mine house." Hebrews 3:2,5-6 — "Moses verily was faithful in all his house, as a servant... but Christ as a son over his own house."'),
('Numbers', 12, 'adults', 5, 'What does the phrase "mouth to mouth" communication with Moses reveal about the uniqueness of Mosaic revelation?', 'It establishes Moses as a mediator of direct, unmediated divine speech — not symbolic visions or dream-impressions but direct verbal communication — making Torah uniquely authoritative', 'All prophets received this kind of communication', 'The phrase is metaphorical for good leadership', 'Moses only heard God in the temple', 'a', 'Numbers 12:8 — "With him will I speak mouth to mouth, even apparently, and not in dark speeches; and the similitude of the LORD shall he behold." Deuteronomy 34:10 confirms: "there arose not a prophet since in Israel like unto Moses, whom the LORD knew face to face."'),
('Numbers', 12, 'adults', 6, 'How does Aaron''s confession in Numbers 12:11-12 demonstrate genuine repentance?', 'Aaron acknowledges they have "done foolishly" and "sinned" — he does not minimize or excuse the act, and his graphic description of Miriam''s condition shows he grasps the severity of the judgment', 'Aaron blamed Miriam entirely', 'Aaron denied wrongdoing', 'Aaron asked God to punish Miriam more', 'a', 'Numbers 12:11-12 — "And Aaron said unto Moses, Alas, my lord, I beseech thee, lay not the sin upon us, wherein we have done foolishly, and wherein we have sinned." Aaron''s immediate, honest confession contrasts with Israel''s repeated hardness of heart.'),
('Numbers', 12, 'adults', 7, 'What social and ceremonial significance did the seven-day exclusion from camp carry for Miriam?', 'Leprosy rendered one ceremonially unclean and socially excluded under Levitical law (Leviticus 13:46) — even a princess of Israel was subject to the same law, teaching that no one is above divine holiness standards', 'The exclusion was a personal preference', 'Seven days was the minimum for any illness', 'Only priests were excluded for leprosy', 'a', 'Numbers 12:14-15 — "Let her be shut out from the camp seven days... And Miriam was shut out from the camp seven days." Leviticus 13:46 prescribes this exact protocol: "he shall dwell alone; without the camp shall his habitation be."'),
('Numbers', 12, 'adults', 8, 'What does the entire nation waiting for Miriam (Numbers 12:15) reveal about her standing in Israel?', 'Despite her sin and punishment, Miriam was so valued as a leader and prophetess that the whole community halted the entire journey for her — showing that discipline does not erase worth', 'The nation waited out of obligation only', 'Miriam was not a significant figure', 'The camp stopped because of bad weather', 'a', 'Numbers 12:15 — "And the people journeyed not till Miriam was brought in again." Micah 6:4 confirms her stature: "I sent before thee Moses, Aaron, and Miriam." She is one of only three named leaders of the exodus generation.');

-- ═══ Numbers Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 13, 'kids', 1, 'How many spies did Moses send to look at the land of Canaan?', 'Twelve — one from each tribe', 'Seven spies', 'Forty spies', 'Three spies', 'a', 'Numbers 13:2 — "Send thou men, that they may search the land of Canaan... of every tribe of their fathers shall ye send a man."'),
('Numbers', 13, 'kids', 2, 'What amazing fruit did the spies bring back from the valley of Eshcol?', 'A giant cluster of grapes so big it took two men to carry it on a pole', 'A large basket of figs', 'A huge watermelon', 'A barrel of honey', 'a', 'Numbers 13:23 — "And they cut down from thence a branch with one cluster of grapes, and they bare it between two upon a staff."'),
('Numbers', 13, 'kids', 3, 'Which spy gave a good report and said the people should go take the land?', 'Caleb', 'Dathan', 'Korah', 'Balaam', 'a', 'Numbers 13:30 — "And Caleb stilled the people before Moses, and said, Let us go up at once, and possess it; for we are well able to overcome it."'),
-- Teens
('Numbers', 13, 'teens', 1, 'How many days did the spies explore the land of Canaan?', 'Forty days', 'Seven days', 'Twenty days', 'Three days', 'a', 'Numbers 13:25 — "And they returned from searching of the land after forty days."'),
('Numbers', 13, 'teens', 2, 'What did the ten unfaithful spies say about the people of Canaan?', 'They said the Canaanites were stronger and taller, and that the spies felt like grasshoppers in their sight', 'They said the land was easy to take', 'They said the people were friendly', 'They said the cities had no walls', 'a', 'Numbers 13:32-33 — "The land, through which we have gone to search it, is a land that eateth up the inhabitants thereof; and all the people that we saw in it are men of a great stature... and we were in our own sight as grasshoppers."'),
('Numbers', 13, 'teens', 3, 'What was the name of the valley where the spies cut the giant cluster of grapes?', 'The brook Eshcol', 'The valley of Jezreel', 'The plain of Moab', 'The valley of Achor', 'a', 'Numbers 13:24 — "The place was called the brook Eshcol, because of the cluster of grapes which the children of Israel cut down from thence."'),
('Numbers', 13, 'teens', 4, 'What was the original name of Joshua before Moses changed it?', 'Oshea', 'Caleb', 'Eleazar', 'Hoshea', 'a', 'Numbers 13:16 — "And Moses called Oshea the son of Nun Jehoshua." (The name Hoshea/Oshea was changed to Joshua/Jehoshua.)'),
('Numbers', 13, 'teens', 5, 'What three groups of giants did the spies report living in the land?', 'The Anakims, descended from the Nephilim, plus the Amalekites, Hittites, Jebusites, Amorites, and Canaanites in their various territories', 'Only the Philistines', 'The Moabites and Ammonites', 'The Egyptians who followed them', 'a', 'Numbers 13:28-29,33 — "The people be strong that dwell in the land... and there we saw the giants, the sons of Anak, which come of the giants: and we were in our own sight as grasshoppers."'),
-- Adults
('Numbers', 13, 'adults', 1, 'What is the significance of the name change from Hoshea to Jehoshua (Joshua) in Numbers 13:16?', 'Hoshea means "salvation"; Jehoshua means "the LORD saves" or "the LORD is salvation" — Moses added the divine name Yah, consecrating Joshua as the one through whom the LORD would accomplish the conquest', 'The names are identical in meaning', 'Moses changed the name as a punishment', 'Joshua requested the name change himself', 'a', 'Numbers 13:16 — "And Moses called Oshea the son of Nun Jehoshua." The addition of the Yah prefix transforms a statement about salvation into a declaration that YHWH is the agent of salvation — pointing forward to Jesus (Yeshua) by the same root.'),
('Numbers', 13, 'adults', 2, 'How does the forty-day spy mission foreshadow the forty-year wilderness penalty?', 'God imposed a year for every day the spies searched (Numbers 14:34) — one day of disobedient spying resulted in one year of wandering, making the punishment proportional to the sin', 'The numbers are coincidental', 'Forty years was a standard term of service', 'The spies recommended the forty-year period', 'a', 'Numbers 14:34 — "After the number of the days in which ye searched the land, even forty days, each day for a year, shall ye bear your iniquities, even forty years." The symmetry is judicial — the punishment mirrors the duration of the act of unbelief.'),
('Numbers', 13, 'adults', 3, 'What is the theological problem with the spies saying "we were in our own sight as grasshoppers" (Numbers 13:33)?', 'The issue is "in our own sight" — they were evaluating themselves by human perception rather than by God''s power; their self-assessment excluded God entirely from the equation', 'The spies were being realistically humble', 'The giants were indeed invincible', 'Physical size determines God''s ability to deliver', 'a', 'Numbers 13:33 — "And we were in our own sight as grasshoppers, and so we were in their sight." The phrase "in our own sight" reveals the fundamental problem: a self-referential faith that does not factor in omnipotence.'),
('Numbers', 13, 'adults', 4, 'What does the description of Canaan as a land that "eateth up the inhabitants thereof" mean in context?', 'The spies were describing the harsh, war-torn nature of the land where constant conflict devoured its people — using it as an argument against conquest, though ironically the same land would support Israel abundantly', 'The land was literally poisonous', 'The climate destroyed crops every year', 'The animals ate the inhabitants', 'a', 'Numbers 13:32 — "The land, through which we have gone to search it, is a land that eateth up the inhabitants thereof." The spies likely meant the land''s contested nature and difficult conditions, but they used it as fear-mongering despite also testifying to its fruitfulness (v.27).'),
('Numbers', 13, 'adults', 5, 'How does Caleb''s statement "we are well able to overcome it" (Numbers 13:30) differ theologically from the ten spies'' assessment?', 'Caleb''s "well able" is a statement of faith that implicitly includes God as the agent of victory; the ten spies calculated only human strength, producing fear, while Caleb calculated divine power, producing confidence', 'Caleb was naive and inexperienced', 'Both positions were equally valid', 'Caleb was simply more optimistic by personality', 'a', 'Numbers 13:30 — "And Caleb stilled the people before Moses, and said, Let us go up at once, and possess it; for we are well able to overcome it." Numbers 14:8-9 clarifies Caleb''s reasoning: "If the LORD delight in us... the LORD is with us: fear them not."'),
('Numbers', 13, 'adults', 6, 'What is the typological significance of the valley of Eshcol''s fruit cluster carried on a pole between two men?', 'Many patristic and Reformed interpreters see this as a type of Christ on the cross — the fruit of the promised land carried on wood between two bearers, pointing to the fruit of redemption brought through the cross', 'The image has no symbolic significance', 'It simply records an agricultural fact', 'The pole represents the Law of Moses', 'a', 'Numbers 13:23 — "And they cut down from thence a branch with one cluster of grapes, and they bare it between two upon a staff." The imagery of life-giving fruit carried on a wooden pole between two companions has been consistently read typologically by interpreters such as Origen and Calvin.'),
('Numbers', 13, 'adults', 7, 'How does the list of Canaanite nations in Numbers 13:29 relate to earlier covenant promises?', 'These are the same nations listed in God''s covenant with Abraham in Genesis 15:18-21, confirming that the conquest is the fulfilment of a centuries-old divine promise — giving theological context to the command to displace them', 'The nations in Numbers 13 are entirely different from Genesis', 'The covenant with Abraham did not name specific peoples', 'The nations had all moved away by the time of the spies', 'a', 'Genesis 15:19-21 lists the Kenites, Kenizzites, Kadmonites, Hittites, Perizzites, Rephaims, Amorites, Canaanites, Girgashites, and Jebusites. Numbers 13:29 names the Amalekites, Hittites, Jebusites, Amorites, and Canaanites, showing partial overlap with the Abrahamic covenant geography.'),
('Numbers', 13, 'adults', 8, 'What does Caleb''s tribal identity as a Kenizzite (cf. Numbers 32:12; Joshua 14:6) reveal about faithfulness and covenant inclusion?', 'Caleb was from a non-Israelite lineage (the Kenizzites were originally Edomite/Canaanite, Genesis 15:19) yet became the exemplar of Israelite faith — showing that covenant faithfulness transcends ethnic origin', 'Caleb was a full-blood Israelite from Judah', 'The Kenizzites were a sub-tribe of Judah', 'Tribal lineage is unimportant in Numbers', 'a', 'Numbers 32:12 — "Save Caleb the son of Jephunneh the Kenezite, and Joshua the son of Nun: for they have wholly followed the LORD." Joshua 14:14 confirms: "Caleb the son of Jephunneh the Kenezite." His inclusion models the later expansion of the covenant to all nations.');

-- ═══ Numbers Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 14, 'kids', 1, 'What did the people of Israel do when they heard the bad report of the spies?', 'They cried all night and said they wanted to go back to Egypt', 'They all went to sleep', 'They sang songs of praise', 'They built a new altar', 'a', 'Numbers 14:1 — "And all the congregation lifted up their voice, and cried; and the people wept that night."'),
('Numbers', 14, 'kids', 2, 'How long did God say the Israelites must wander in the wilderness because of their unbelief?', 'Forty years', 'Ten years', 'One year', 'Seven years', 'a', 'Numbers 14:33 — "And your children shall wander in the wilderness forty years."'),
('Numbers', 14, 'kids', 3, 'Which two faithful spies did not agree with the bad report and were not punished with death?', 'Caleb and Joshua', 'Aaron and Moses', 'Korah and Dathan', 'Nadab and Abihu', 'a', 'Numbers 14:30 — "Save Caleb the son of Jephunneh, and Joshua the son of Nun."'),
-- Teens
('Numbers', 14, 'teens', 1, 'What did the people say they wished had happened to them instead of going to Canaan?', 'They wished they had died in Egypt or in the wilderness', 'They wished Moses had never been born', 'They wished they could go to Babylon', 'They wished they had stayed slaves', 'a', 'Numbers 14:2 — "Would God that we had died in the land of Egypt! or would God we had died in this wilderness!"'),
('Numbers', 14, 'teens', 2, 'What did Moses say to God to persuade Him not to destroy Israel?', 'That the Egyptians and surrounding nations would hear of it and say God was not able to bring Israel into the land', 'That Israel deserved another chance', 'That the people were young and ignorant', 'That the spies had given a misleading report', 'a', 'Numbers 14:13-16 — "And Moses said unto the LORD... the Egyptians shall hear it... Because the LORD was not able to bring this people into the land which he sware unto them, therefore he hath slain them in the wilderness."'),
('Numbers', 14, 'teens', 3, 'What verse did Moses quote from when he appealed to God''s character and mercy?', 'He quoted God''s own description of Himself as merciful, longsuffering, and forgiving, given at Sinai', 'He quoted a psalm of David', 'He quoted the words of Abraham', 'He quoted the law about sacrifices', 'a', 'Numbers 14:18 — "The LORD is longsuffering, and of great mercy, forgiving iniquity and transgression, and by no means clearing the guilty." Moses echoes Exodus 34:6-7 where God proclaimed His own name.'),
('Numbers', 14, 'teens', 4, 'What happened to the ten spies who gave the evil report?', 'They died by a plague before the LORD', 'They were sent to Egypt', 'They were made servants', 'They were banished to the mountains', 'a', 'Numbers 14:37 — "Even those men that did bring up the evil report upon the land, died by the plague before the LORD."'),
('Numbers', 14, 'teens', 5, 'What happened when some Israelites presumptuously tried to attack Canaan after God''s judgment was pronounced?', 'They were defeated and beaten back by the Amalekites and Canaanites because the LORD was not with them', 'They successfully captured a city', 'They turned back before reaching any enemies', 'Moses led them and they won', 'a', 'Numbers 14:45 — "Then the Amalekites came down, and the Canaanites which dwelt in that hill, and smote them, and discomfited them, even unto Hormah."'),
-- Adults
('Numbers', 14, 'adults', 1, 'How does Moses'' intercession in Numbers 14:13-19 demonstrate the theology of praying God''s own character back to Him?', 'Moses does not appeal to Israel''s merit but to God''s reputation and His own self-proclaimed attributes (Exodus 34:6-7), showing that the strongest intercessory prayers are grounded in revealed divine character', 'Moses appealed primarily to Israel''s suffering', 'Moses invented new arguments not found in Torah', 'Prayer based on God''s character is presumptuous', 'a', 'Numbers 14:17-18 — "And now, I beseech thee, let the power of my lord be great, according as thou hast spoken, saying, The LORD is longsuffering, and of great mercy." Moses quotes back to God exactly what God declared at Sinai (Exodus 34:6).'),
('Numbers', 14, 'adults', 2, 'What is the theological significance of God saying He will "smite them with the pestilence, and disinherit them" and make of Moses a greater nation?', 'It is a test of Moses'' selflessness — the same offer was made at Sinai (Exodus 32:10) and Moses refuses again, demonstrating that true intercession sacrifices personal advantage for the community', 'Moses accepted the offer both times', 'God was not serious about the offer', 'The offer revealed Moses'' secret ambition', 'a', 'Numbers 14:12 — "I will smite them with the pestilence, and disinherit them, and will make of thee a greater nation." Moses'' refusal echoes Exodus 32:10-12, showing consistent selfless intercession that the NT holds up as the model of prayer.'),
('Numbers', 14, 'adults', 3, 'How does the phrase "visiting the iniquity of the fathers upon the children unto the third and fourth generation" (Numbers 14:18) function in Moses'' intercession?', 'Moses quotes the full divine attribute — including both mercy and judgment — to show he is not asking God to ignore justice but to exercise mercy within His own stated character, not in violation of it', 'Moses was asking God to punish children for parents'' sins', 'The phrase was being used as a curse', 'Moses was quoting a Canaanite proverb', 'a', 'Numbers 14:18 — "forgiving iniquity and transgression, and by no means clearing the guilty, visiting the iniquity of the fathers upon the children." Moses includes the full context of Exodus 34:6-7, appealing for the mercy side of the same divine nature.'),
('Numbers', 14, 'adults', 4, 'What does "wholly followed the LORD" mean in Numbers 14:24 regarding Caleb, and what Hebrew phrase is behind it?', 'The Hebrew is male'' acharei YHWH — literally "filled up after the LORD" — conveying wholehearted, unreserved, undivided devotion as opposed to the half-hearted obedience of the rest of Israel', 'It means Caleb never sinned', 'It means Caleb was the fastest runner', 'It is a military term for close pursuit', 'a', 'Numbers 14:24 — "But my servant Caleb, because he had another spirit with him, and hath followed me fully." The phrase "followed me fully" (male'' acharei) indicates the kind of devoted faith that does not hold back any part of one''s allegiance from God.'),
('Numbers', 14, 'adults', 5, 'How does the death of the rebellious generation (Numbers 14:29-35) relate to the typology of death in the wilderness in 1 Corinthians 10?', 'Paul uses the wilderness generation as a warning to Christians — "with many of them God was not well pleased: for they were overthrown in the wilderness" — showing that physical participation in covenant rites does not guarantee spiritual safety', 'Paul never references this passage', 'The wilderness deaths are unrelated to Christian doctrine', 'Paul uses the passage only to praise Moses', 'a', '1 Corinthians 10:5 — "But with many of them God was not well pleased: for they were overthrown in the wilderness." Paul draws on Numbers 14 to warn NT believers that professing covenant membership without faith leads to the same judgment.'),
('Numbers', 14, 'adults', 6, 'What is the sin of presumption illustrated in Numbers 14:44-45, and how does it contrast with the earlier sin of unbelief?', 'The people first sinned by refusing to go when God commanded them; then they sinned by going when God forbade it — both sins are failures to trust God''s word and timing, simply reversed in direction', 'Presumption is always worse than unbelief', 'The second attempt was acceptable to God', 'God commanded them to try a second time', 'a', 'Numbers 14:41-42,45 — "Wherefore now do ye transgress the commandment of the LORD? but it shall not prosper... Go not up; for the LORD is not among you; that ye be not smitten before your enemies." Hebrews 3:19 identifies the root sin as unbelief.'),
('Numbers', 14, 'adults', 7, 'How does God''s pardon in Numbers 14:20 ("I have pardoned according to thy word") coexist with continued judgment (the forty-year sentence)?', 'Pardon removes the ultimate penalty of immediate destruction but does not eliminate all temporal consequences of sin — showing that forgiveness and discipline can coexist in the divine economy', 'Pardon meant no punishment at all', 'The forty years was a reward', 'God changed His mind again after pardoning them', 'a', 'Numbers 14:20-23 — "I have pardoned according to thy word: But as truly as I live, all the earth shall be filled with the glory of the LORD. Because all those men... have not hearkened unto my voice... they shall not see the land." Forgiveness is real, but consequences remain.'),
('Numbers', 14, 'adults', 8, 'What is the significance of the phrase "another spirit" in Caleb in Numbers 14:24 compared to the spirit of fear and rebellion in the other spies?', 'Caleb''s "another spirit" (Hebrew: ruach acheret) means a different inner disposition — a spirit of faith, courage, and God-centeredness that perceives the same circumstances entirely differently, producing obedience rather than fear', 'The phrase refers to demon possession', 'Caleb received a special angelic spirit', 'All the spies had the same spirit but different opinions', 'a', 'Numbers 14:24 — "But my servant Caleb, because he had another spirit with him, and hath followed me fully." The contrast is between a spirit dominated by fear of man versus a spirit dominated by faith in God — the same contrast Paul draws in 2 Timothy 1:7.');

-- ═══ Numbers Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 15, 'kids', 1, 'What did God command the Israelites to wear on the corners of their garments to help them remember His commandments?', 'Fringes with a blue ribbon', 'Gold rings', 'Red cloth patches', 'Small bells', 'a', 'Numbers 15:38 — "Speak unto the children of Israel, and bid them that they make them fringes in the borders of their garments throughout their generations, and that they put upon the fringe of the borders a ribband of blue."'),
('Numbers', 15, 'kids', 2, 'What happened to a man who was found picking up sticks on the Sabbath day?', 'He was stoned to death outside the camp', 'He was made to pay a fine', 'He was sent away from Israel', 'He was forgiven after apologizing', 'a', 'Numbers 15:35 — "And the LORD said unto Moses, The man shall be surely put to death: all the congregation shall stone him with stones without the camp."'),
('Numbers', 15, 'kids', 3, 'What were the fringes on garments meant to help Israel remember?', 'All the commandments of the LORD', 'The names of the twelve tribes', 'The journey through the wilderness', 'The laws about offerings', 'a', 'Numbers 15:39 — "And it shall be unto you for a fringe, that ye may look upon it, and remember all the commandments of the LORD, and do them."'),
-- Teens
('Numbers', 15, 'teens', 1, 'What is the difference between sins committed "through ignorance" and sins done "with a high hand" according to Numbers 15?', 'Ignorant sins had atonement provisions through offerings; high-handed (presumptuous) sins had no sacrifice — the person was to be cut off from Israel', 'Both sins were treated identically', 'High-handed sins were less serious', 'Ignorance was not considered a sin at all', 'a', 'Numbers 15:30 — "But the soul that doeth ought presumptuously... the same reproacheth the LORD; and that soul shall be cut off from among his people." Verses 27-29 provide the sacrifice for unintentional sin.'),
('Numbers', 15, 'teens', 2, 'What offering did God command Israel to give when they first entered the land and ate bread from it?', 'A heave offering — a cake of the first of their dough — as a contribution to the LORD', 'A burnt offering of a bull', 'A peace offering of two lambs', 'A sin offering of five pigeons', 'a', 'Numbers 15:20-21 — "Ye shall offer up a cake of the first of your dough for an heave offering: as ye do the heave offering of the threshingfloor, so shall ye heave it."'),
('Numbers', 15, 'teens', 3, 'What was the purpose of the "meat offering" (grain offering) that accompanied animal sacrifices according to Numbers 15?', 'It was to be a pleasing aroma to the LORD, accompanying burnt offerings and peace offerings according to specific proportions of flour, oil, and wine', 'It replaced the animal sacrifice', 'It was only for the priests to eat', 'It was given to the poor', 'a', 'Numbers 15:4-5 — "Then shall he that offereth his offering unto the LORD bring a meat offering of a tenth deal of flour mingled with the fourth part of an hin of oil. And the fourth part of an hin of wine for a drink offering."'),
('Numbers', 15, 'teens', 4, 'What phrase in Numbers 15 emphasizes that the same laws applied to both native Israelites and foreigners living among them?', '"One law and one manner shall be for you, and for the stranger that sojourneth with you"', '"Only the sons of Israel shall obey these laws"', '"The stranger shall make his own laws"', '"Different rules apply to each nation"', 'a', 'Numbers 15:16 — "One law and one manner shall be for you, and for the stranger that sojourneth with you: it shall be a statute for ever in your generations."'),
('Numbers', 15, 'teens', 5, 'What did the LORD command regarding the man caught gathering sticks on the Sabbath before announcing the sentence?', 'He was placed in custody while the congregation sought the LORD''s judgment — the sentence had not yet been declared', 'He was immediately executed', 'He was released after questioning', 'Moses decided the sentence on his own', 'a', 'Numbers 15:34 — "And they put him in ward, because it was not declared what should be done to him."'),
-- Adults
('Numbers', 15, 'adults', 1, 'How does the placement of Numbers 15 immediately after the judgment of chapter 14 carry a message of grace?', 'God gives detailed laws about offerings in the promised land even while pronouncing that the current generation will never enter it — signalling that the covenant continues for the next generation and God''s purposes are not frustrated by human failure', 'The placement is purely editorial', 'Chapter 15 reverses the judgment of chapter 14', 'The laws were for the wilderness period only', 'a', 'Numbers 15:2 — "When ye be come into the land of your habitations, which I give unto you..." After the disaster of chapter 14, God immediately speaks of future land entry, assuring that covenant promises extend to the faithful next generation.'),
('Numbers', 15, 'adults', 2, 'What is the theological significance of the wine (hin of wine) included in the offering prescriptions of Numbers 15?', 'The drink offering of wine poured out before the LORD is a symbol of joy and consecration — later the NT uses this imagery for Christ''s blood poured out (Matthew 26:28) and Paul''s own martyrdom (Philippians 2:17, 2 Timothy 4:6)', 'Wine in offerings was a Canaanite borrowing', 'Wine was included only for taste purposes', 'The drink offering replaced the blood sacrifice', 'a', 'Numbers 15:5-7 — "And the fourth part of an hin of wine for a drink offering... and for a drink offering thou shalt offer the third part of an hin of wine." Paul writes in Philippians 2:17: "yea, and if I be offered upon the sacrifice and service of your faith, I joy."'),
('Numbers', 15, 'adults', 3, 'What does the phrase "blaspheming the LORD" and "reproacheth the LORD" (Numbers 15:30) reveal about the nature of deliberate, high-handed sin?', 'Presumptuous sin is not merely moral failure but an act of contempt against the divine Lawgiver — it is a statement that God''s commands are irrelevant, amounting to practical atheism or rebellion against divine sovereignty', 'Presumptuous sin is simply a stronger form of inadvertent sin', 'The phrase is rhetorical hyperbole', 'Blasphemy was only verbal', 'a', 'Numbers 15:30 — "But the soul that doeth ought presumptuously... the same reproacheth the LORD: and that soul shall be cut off." The Hebrew root for "reproacheth" (gadaph) means to revile or blaspheme — deliberate sin is an assault on the character of God.'),
('Numbers', 15, 'adults', 4, 'How does the case of the Sabbath-breaker in Numbers 15:32-36 relate to the Mosaic covenant''s capital penalty structure?', 'It demonstrates that Sabbath-breaking was a capital offense (Exodus 31:14-15) because the Sabbath was a covenant sign — breaking it publicly was tantamount to repudiating the entire covenant relationship with YHWH', 'The Sabbath law only applied in the tabernacle', 'Stoning was only for idolatry', 'The penalty was unusually harsh for minor violations', 'a', 'Exodus 31:14 — "Ye shall keep the sabbath therefore; for it is holy unto you: every one that defileth it shall surely be put to death." Numbers 15:35 executes this provision, establishing that the covenant sign carried the full weight of covenantal law.'),
('Numbers', 15, 'adults', 5, 'What is the typological significance of the blue ribbon on the fringes in Numbers 15:38?', 'Blue (Hebrew: tekhelet) was the color of the tabernacle curtains and priestly garments, symbolizing heaven and divine holiness — wearing it on the fringe reminded every Israelite that they were a kingdom of priests (Exodus 19:6) called to heavenly standards', 'Blue was simply the most available dye', 'The color had no symbolic meaning', 'Blue was the color of royalty only', 'a', 'Numbers 15:38-40 — "Put upon the fringe of the borders a ribband of blue... that ye may remember all the commandments of the LORD." The tekhelet (sky-blue) dye from the hilazon shellfish connected ordinary clothing to the sacred space of the tabernacle.'),
('Numbers', 15, 'adults', 6, 'How does the New Testament''s treatment of the fringes (tzitzit) in Matthew 9:20 and 14:36 relate to their intended purpose in Numbers 15?', 'People touched the hem of Jesus'' garment expecting healing — the fringe/border (kraspedon) was the tzitzit — showing that Jesus embodied the holiness and divine commandment-keeping the fringes were meant to signify, making Him the fulfilment of what the garment borders pointed to', 'The gospel references are unrelated to Numbers 15', 'The hem of Jesus'' garment was merely decorative', 'Only Jewish Christians would understand the reference', 'a', 'Numbers 15:38-40 and Matthew 14:36 — "And besought him that they might only touch the hem of his garment: and as many as touched were made perfectly whole." The tzitzit that recalled the commandments was now the border of the One who perfectly kept them.'),
('Numbers', 15, 'adults', 7, 'What does the sin offering for the "whole congregation" sinning through ignorance (Numbers 15:24-26) reveal about corporate sin?', 'Corporate entities can sin collectively — not just individuals — and require corporate atonement; this establishes the principle that communities bear shared moral responsibility before God', 'Only individuals sin; communities cannot', 'Corporate sin offerings were voluntary', 'The congregation offering was for the leaders only', 'a', 'Numbers 15:25-26 — "The priest shall make an atonement for all the congregation of the children of Israel, and it shall be forgiven them; for it is an ignorance: and they shall bring their offering, a sacrifice made by fire unto the LORD."'),
('Numbers', 15, 'adults', 8, 'How does the law of first fruits of dough (Numbers 15:20-21) connect to Paul''s argument in Romans 11:16?', 'Paul cites the firstfruits principle — "if the firstfruit be holy, the lump is also holy" — to argue that the patriarchs'' holiness consecrated the Jewish nation, and the remnant''s faith sanctifies the broader community, drawing directly on the Numbers 15 concept', 'Romans 11:16 references the firstfruits of harvest, not dough', 'Paul''s argument is unrelated to Numbers', 'The firstfruits principle was only ceremonial', 'a', 'Numbers 15:20-21 — "Ye shall offer up a cake of the first of your dough." Romans 11:16 — "For if the firstfruit be holy, the lump is also holy: and if the root be holy, so are the branches." Paul applies the Numbers principle to argue for Israel''s continuing holiness before God.');

-- ═══ Numbers Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 16, 'kids', 1, 'What happened to Korah and his followers when they rebelled against Moses and Aaron?', 'The earth opened up and swallowed them alive', 'They were struck by lightning', 'They were sent into the desert', 'They were put in prison', 'a', 'Numbers 16:32 — "And the earth opened her mouth, and swallowed them up, and their houses, and all the men that appertained unto Korah, and all their goods."'),
('Numbers', 16, 'kids', 2, 'What happened to the two hundred and fifty men who offered incense when they should not have?', 'Fire came from the LORD and consumed them', 'They ran away and were safe', 'They were forgiven after saying sorry', 'They became priests', 'a', 'Numbers 16:35 — "And there came out a fire from the LORD, and consumed the two hundred and fifty men that offered incense."'),
('Numbers', 16, 'kids', 3, 'How many people were killed in the plague that came after Korah''s rebellion?', 'Fourteen thousand seven hundred people', 'Four hundred people', 'One thousand people', 'Forty people', 'a', 'Numbers 16:49 — "Now they that died in the plague were fourteen thousand and seven hundred, beside them that died about the matter of Korah."'),
-- Teens
('Numbers', 16, 'teens', 1, 'Who were the three main leaders of the rebellion against Moses and Aaron?', 'Korah the Levite, and Dathan and Abiram of the tribe of Reuben', 'Balaam, Balak, and Barak', 'Nadab, Abihu, and Eleazar', 'Othniel, Caleb, and Joshua', 'a', 'Numbers 16:1 — "Now Korah, the son of Izhar, the son of Kohath, the son of Levi, and Dathan and Abiram, the sons of Eliab, and On, the son of Peleth, sons of Reuben, took men."'),
('Numbers', 16, 'teens', 2, 'What was the core complaint of Korah and his company against Moses and Aaron?', 'They said all the congregation was holy and accused Moses and Aaron of lifting themselves above the assembly of the LORD', 'They complained about the quality of food', 'They demanded more land for their tribe', 'They objected to the census', 'a', 'Numbers 16:3 — "Ye take too much upon you, seeing all the congregation are holy, every one of them, and the LORD is among them: wherefore then lift ye up yourselves above the congregation of the LORD?"'),
('Numbers', 16, 'teens', 3, 'What test did Moses propose to determine who was truly chosen by God as priests?', 'Each man should take a censer with incense and present it before the LORD — the man God chose would be the holy one', 'They would draw lots', 'They would fight in single combat', 'They would fast for seven days', 'a', 'Numbers 16:6-7 — "Take you censers, Korah, and all his company; And put fire therein, and put incense in them before the LORD to morrow: and it shall be that the man whom the LORD doth choose, he shall be holy."'),
('Numbers', 16, 'teens', 4, 'What did Dathan and Abiram refuse to do when Moses summoned them, and what did they accuse him of?', 'They refused to come up and accused Moses of failing to bring them into a land of milk and honey, calling Egypt the land of milk and honey instead', 'They agreed to meet but brought weapons', 'They sent a written complaint to the elders', 'They prepared to attack Moses physically', 'a', 'Numbers 16:12-14 — "And Moses sent to call Dathan and Abiram... And they said, We will not come up... Thou hast not brought us into a land that floweth with milk and honey... Wilt thou put out the eyes of these men? we will not come up."'),
('Numbers', 16, 'teens', 5, 'How did Aaron stop the plague that was killing the people after Korah''s rebellion?', 'He took a censer with fire and incense and stood between the dead and the living to make atonement', 'He offered a bull as a burnt offering', 'He prayed from inside the tabernacle', 'He commanded the people to wash themselves', 'a', 'Numbers 16:47-48 — "And Aaron took as Moses commanded, and ran into the midst of the congregation; and, behold, the plague was begun among the people: and he put on incense, and made an atonement for the people. And he stood between the dead and the living; and the plague was stayed."'),
-- Adults
('Numbers', 16, 'adults', 1, 'What is the deeper theological error in Korah''s argument that "all the congregation are holy" (Numbers 16:3)?', 'Korah correctly states a general truth (Exodus 19:6 — "ye shall be unto me a kingdom of priests") but wrongly uses it to abolish all distinctions of calling and office — confusing positional holiness with functional calling', 'Korah''s argument was entirely false', 'All Israelites were indeed ordained priests', 'Moses had invented the priestly hierarchy without God''s command', 'a', 'Numbers 16:3 uses Exodus 19:6 logic but commits the error of collapsing the distinction between the general priesthood of the nation and the specific Aaronic priesthood — a distinction God Himself established in earlier chapters of Numbers.'),
('Numbers', 16, 'adults', 2, 'How does Korah''s rebellion against Moses foreshadow the NT warning against those who "perish in the gainsaying of Core" (Jude 11)?', 'Jude uses Korah as the paradigm of those who reject divinely appointed authority for self-promoted ministry — the same spirit that despises God''s ordained leadership structure is still active in apostasy', 'Jude''s reference is to a different Korah', 'The warning in Jude applies only to the Levites', 'Korah''s sin was primarily ceremonial, not moral', 'a', 'Jude 11 — "Woe unto them! for they have gone in the way of Cain, and ran greedily after the error of Balaam for reward, and perished in the gainsaying of Core." The three rebels (Cain, Balaam, Korah) represent jealousy, greed, and insubordination respectively.'),
('Numbers', 16, 'adults', 3, 'What does the unique punishment of the earth swallowing Korah (Numbers 16:30-33) indicate about the nature of his sin?', 'Moses frames it as a sign that God would do a "new thing" — an unprecedented judgment for an unprecedented kind of rebellion against divinely appointed leadership, demonstrating that defying God''s ordained order is not a minor infraction', 'The earthquake was a natural coincidence', 'The punishment was disproportionate to the sin', 'Moses chose this punishment himself', 'a', 'Numbers 16:30 — "But if the LORD make a new thing, and the earth open her mouth, and swallow them up, with all that appertain unto them, and they go down quick into the pit; then ye shall understand that these men have provoked the LORD." Moses frames it as a divine sign, not mere punishment.'),
('Numbers', 16, 'adults', 4, 'What is the meaning of the bronze censers being hammered into altar plating (Numbers 16:38-40) as a memorial?', 'The censers became a perpetual warning sign — their bronze covering the altar reminded Israel that it was holy and that approaching God outside of appointed means results in death, embedding judgment into the worship furniture itself', 'The bronze was recycled for economic reasons', 'The memorial was optional and rarely seen', 'The censers were buried with the rebels', 'a', 'Numbers 16:38-40 — "The censers of these sinners against their own souls, let them make them broad plates for a covering of the altar... to be a memorial unto the children of Israel, that no stranger, which is not of the seed of Aaron, come near to offer incense before the LORD."'),
('Numbers', 16, 'adults', 5, 'How does Aaron''s standing "between the dead and the living" with the incense censer (Numbers 16:48) typologically prefigure Christ''s mediatorial work?', 'Aaron''s physical act of standing in the breach between death and life, making atonement to stop the plague, is a type of Christ who stands between sinful humanity and divine wrath, making atonement through His own person', 'Aaron was simply following a procedural requirement', 'The imagery has no typological significance', 'Moses rather than Aaron is the type of Christ', 'a', 'Numbers 16:48 — "And he stood between the dead and the living; and the plague was stayed." Hebrews 7:25 — "He ever liveth to make intercession for them." Aaron''s intercessory act with incense (a type of prayer) points to Christ''s eternal, effective intercession.'),
('Numbers', 16, 'adults', 6, 'What does the people''s murmuring against Moses and Aaron in Numbers 16:41 (the day after the rebellion was crushed) reveal about the depth of Israel''s sin?', 'They blamed Moses and Aaron for the death of the rebels rather than acknowledging God''s just judgment — showing that when people are determined to rebel, even direct divine intervention does not change the heart', 'The people were right to be confused', 'The second murmuring was justified', 'God was too harsh and the people''s complaint was valid', 'a', 'Numbers 16:41 — "But on the morrow all the congregation of the children of Israel murmured against Moses and against Aaron, saying, Ye have killed the people of the LORD." After the earth opened, fire fell, and a plague began, they still hardened their hearts.'),
('Numbers', 16, 'adults', 7, 'What does Moses'' falling on his face in Numbers 16:4,22,45 reveal about his leadership posture throughout the rebellion?', 'Moses consistently responds to crisis with prostration before God rather than self-defense or retaliation — modeling that the leader''s first resort is prayer and humility before divine authority, not human power', 'Moses was physically frightened', 'The gesture was a cultural formality only', 'Moses fell due to exhaustion', 'a', 'Numbers 16:4 — "And when Moses heard it, he fell upon his face." Numbers 16:22 — "And they fell upon their faces." Numbers 16:45 — "And they fell upon their faces." The repeated posture throughout the crisis underscores that Moses'' power came from sustained dependence on God.'),
('Numbers', 16, 'adults', 8, 'How does Korah''s rebellion reflect the broader tension between the Kohathite Levites'' tabernacle duties and their exclusion from altar service?', 'Korah represents the Kohathite Levites who had significant tabernacle transport duties but no altar access — their rebellion reflects institutional frustration with priestly hierarchy, but Moses'' response establishes that divine institution outweighs human grievance', 'The rebellion was purely personal jealousy with no structural dimension', 'The Kohathites had no legitimate duties before this', 'Moses invented the priestly structure during the rebellion', 'a', 'Numbers 16:9-10 — "Seemeth it but a small thing unto you, that the God of Israel hath separated you from the congregation of Israel, to bring you near to himself to do the service of the tabernacle of the LORD... and seek ye the priesthood also?" God''s response validates the structure He Himself ordained.');

-- ═══ Numbers Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 17, 'kids', 1, 'What miracle happened to Aaron''s rod overnight in the tabernacle?', 'It budded, blossomed, and produced ripe almonds', 'It turned into a snake', 'It glowed with light', 'It floated in the air', 'a', 'Numbers 17:8 — "And, behold, the rod of Aaron for the house of Levi was budded, and brought forth buds, and bloomed blossoms, and yielded almonds."'),
('Numbers', 17, 'kids', 2, 'How many rods were placed in the tabernacle for the test — one for each tribe?', 'Twelve rods, one for each tribe of Israel', 'Seven rods', 'Three rods', 'Forty rods', 'a', 'Numbers 17:2 — "Speak unto the children of Israel, and take of every one of them a rod according to the house of their fathers, of all their princes according to the house of their fathers twelve rods."'),
('Numbers', 17, 'kids', 3, 'Whose name was written on the rod for the tribe of Levi?', 'Aaron''s name', 'Moses'' name', 'Joshua''s name', 'Caleb''s name', 'a', 'Numbers 17:3 — "And thou shalt write Aaron''s name upon the rod of Levi."'),
-- Teens
('Numbers', 17, 'teens', 1, 'Why did God command the rod miracle — what problem was it meant to solve?', 'To end the murmurings of the children of Israel so they would no longer complain against Moses and Aaron', 'To show that Levi was the largest tribe', 'To teach the people how to grow almond trees', 'To replace the bronze censers on the altar', 'a', 'Numbers 17:5 — "And it shall come to pass, that the man''s rod, whom I shall choose, shall blossom: and I will make to cease from me the murmurings of the children of Israel, whereby they murmur against you."'),
('Numbers', 17, 'teens', 2, 'Where were the twelve rods placed overnight?', 'Before the LORD in the tabernacle of witness', 'Outside the camp under a tree', 'In Moses'' tent', 'In the ark of the covenant', 'a', 'Numbers 17:7 — "And Moses laid up the rods before the LORD in the tabernacle of witness."'),
('Numbers', 17, 'teens', 3, 'What did God command Moses to do with Aaron''s rod after the miracle?', 'Bring it back before the testimony to be kept as a token against the rebels', 'Burn it as a sin offering', 'Give it to Aaron to carry always', 'Plant it in the ground', 'a', 'Numbers 17:10 — "And the LORD said unto Moses, Bring Aaron''s rod again before the testimony, to be kept for a token against the rebels."'),
('Numbers', 17, 'teens', 4, 'What did the people of Israel say after seeing God''s repeated judgments and the rod miracle?', 'They feared they would all die and be consumed — "Whosoever cometh any thing near unto the tabernacle of the LORD shall die"', 'They praised God and celebrated', 'They asked for a new leader', 'They decided to return to Egypt', 'a', 'Numbers 17:12-13 — "And the children of Israel spake unto Moses, saying, Behold, we die, we perish, we all perish. Whosoever cometh any thing near unto the tabernacle of the LORD shall die: shall we be consumed with dying?"'),
('Numbers', 17, 'teens', 5, 'What was unique about Aaron''s rod compared to the other eleven rods in the tabernacle?', 'Only Aaron''s rod produced living growth — buds, blossoms, and ripe almonds — while all the other rods remained dead dry wood', 'All the rods produced some growth', 'Aaron''s rod produced a different fruit', 'Moses'' rod also budded', 'a', 'Numbers 17:8-9 — "And, behold, the rod of Aaron for the house of Levi was budded, and brought forth buds, and bloomed blossoms, and yielded almonds. And Moses brought out all the rods from before the LORD unto all the children of Israel."'),
-- Adults
('Numbers', 17, 'adults', 1, 'How does Aaron''s budding rod demonstrate the principle that divine calling produces life while human presumption produces nothing?', 'Dead wood supernaturally bearing fruit represents God''s sovereign choice conferring life and fruitfulness to what is naturally inert — no human striving or political maneuvering can produce what only God''s choice bestows', 'The rod miracle was primarily about agricultural symbolism', 'Any Levite with faith could have produced the same result', 'The miracle was intended only as a memory test', 'a', 'Numbers 17:8 — "The rod of Aaron for the house of Levi was budded, and brought forth buds, and bloomed blossoms, and yielded almonds." The rod — dry, dead, cut wood — producing mature fruit in one night is a vivid image of resurrection life from divine election.'),
('Numbers', 17, 'adults', 2, 'How does Aaron''s rod appear in Hebrews 9:4 and what is its significance in the New Testament context?', 'Hebrews lists it among the ark''s contents as part of the old covenant''s sanctuary furniture — linking it to the entire apparatus of priestly mediation that Christ fulfils and supersedes as the eternal High Priest', 'Hebrews never mentions Aaron''s rod', 'The rod was discarded before the NT era', 'Hebrews condemns the rod as a symbol of legalism', 'a', 'Hebrews 9:4 — "Which had the golden censer, and the ark of the covenant overlaid round about with gold, wherein was the golden pot that had manna, and Aaron''s rod that budded, and the tables of the covenant." The rod stands as evidence of God''s chosen priesthood, now perfectly expressed in Christ.'),
('Numbers', 17, 'adults', 3, 'What is the typological connection between Aaron''s dead rod that budded and the resurrection of Christ?', 'Both involve the giving of life to what is dead by divine power — Aaron''s priesthood validated by resurrection imagery prefigures Christ''s priesthood confirmed by His literal resurrection (Romans 1:4; Hebrews 7:16)', 'The rod''s budding was purely botanical with no spiritual significance', 'Resurrection imagery is absent from the Old Testament', 'Only the NT uses the concept of life coming from death', 'a', 'Romans 1:4 — "declared to be the Son of God with power... by the resurrection from the dead." Just as Aaron''s priesthood was confirmed by the rod''s impossible resurrection-life, Christ''s eternal priesthood was confirmed by His resurrection.'),
('Numbers', 17, 'adults', 4, 'What does the simultaneous presence of buds, blossoms, and ripe almonds on Aaron''s rod indicate symbolically?', 'The three stages of development appearing simultaneously — bud, blossom, ripe fruit — indicate a supernatural fullness of life, suggesting that God''s chosen priest bears complete and perfect fruitfulness at all stages simultaneously', 'The stages simply record the order in which they appeared overnight', 'The three stages are only descriptive botanical detail', 'Almonds were chosen because of their commercial value', 'a', 'Numbers 17:8 — "budded, and brought forth buds, and bloomed blossoms, and yielded almonds." The Hebrew presents all three states as simultaneously present — a living parable of the fullness of life in God''s chosen servant, impossible by natural law.'),
('Numbers', 17, 'adults', 5, 'Why might almonds specifically be significant in this context, given Aaron''s role and the tabernacle furniture?', 'The almond (shaqed) is linked to the word "watching" (shoqed) — the first tree to blossom in spring; furthermore, the tabernacle lampstand was shaped like almond blossoms (Exodus 25:33), connecting Aaron''s rod to the priestly lampstand ministry', 'Almonds were the most common fruit in Canaan', 'The tribe of Levi had almond trees as their symbol', 'Almonds were chosen at random', 'a', 'Exodus 25:33 — "Three bowls made like unto almonds, with a knower and a flower in one branch." The menorah''s almond design directly links the lighting of God''s presence to the almond-bearing rod of Aaron.'),
('Numbers', 17, 'adults', 6, 'How does the public display of all twelve rods before the congregation (Numbers 17:9) function as an epistemological proof of divine authorization?', 'By presenting all rods simultaneously — each with the leader''s name — the miracle is verifiable, comparative, and public: no one can claim the process was rigged or that other rods were not fairly tested', 'The rods were shown in private to prevent panic', 'Only the tribal leaders saw the rods', 'Moses could have substituted rods secretly', 'a', 'Numbers 17:9 — "And Moses brought out all the rods from before the LORD unto all the children of Israel: and they looked, and took every man his rod." The public verification before all the congregation eliminates the possibility of fraud and makes the evidence communally owned.'),
('Numbers', 17, 'adults', 7, 'What spiritual condition does the people''s cry of despair ("we all perish") in Numbers 17:12-13 reveal, despite the miracle being meant to reassure them?', 'Rather than responding to God''s gracious sign with grateful submission, Israel responds with terror and despair — revealing a conscience burdened by guilt and a failure to grasp that the same God who judges rebels also provides a mediating priest', 'The response shows healthy reverence', 'Their fear was the correct theological response', 'God intended the rod to create fear rather than confidence', 'a', 'Numbers 17:12-13 — "We die, we perish, we all perish... shall we be consumed with dying?" Immediately after God validates His priest, Israel fears the priest''s role rather than taking comfort in it — foreshadowing the need for a better priest who makes access to God safe and sure.'),
('Numbers', 17, 'adults', 8, 'How does the ark''s storage of Aaron''s rod, the manna pot, and the tablets (Hebrews 9:4) form a unified theological statement about Israel''s wilderness failures?', 'Each object memorializes a specific rebellion: the manna pot (refusing God''s provision — Numbers 11), the tablets (the golden calf — Exodus 32), and the rod (Korah''s rebellion — Numbers 16-17) — together they make the ark a witness against Israel''s sinfulness, showing the need for a better covenant', 'The objects were stored for historical documentation only', 'Each object commemorates a victory', 'The rod was stored separately from the other objects', 'a', 'Hebrews 9:4 lists the ark''s three contents together. Each is a monument to the failure of the old covenant people: they murmured about food, broke the law, and rejected God''s priesthood — all pointing to the need for Christ who is the bread of life, the law''s fulfilment, and the eternal priest.');

-- ═══ Numbers Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 18, 'kids', 1, 'What did God tell Aaron the priests and Levites were to receive instead of a land inheritance in Canaan?', 'The tithes and offerings of Israel — God Himself was their inheritance', 'The best fields in the Jordan valley', 'A special city in Canaan', 'Gold from the tabernacle treasury', 'a', 'Numbers 18:20 — "And the LORD spake unto Aaron, Thou shalt have no inheritance in their land, neither shalt thou have any part among them: I am thy part and thine inheritance among the children of Israel."'),
('Numbers', 18, 'kids', 2, 'What did the Levites receive from the children of Israel as payment for their work at the tabernacle?', 'Tithes — a tenth of everything Israel produced', 'Half of all the crops', 'The firstborn animals', 'The silver from the census', 'a', 'Numbers 18:21 — "And, behold, I have given the children of Levi all the tenth in Israel for an inheritance, for their service which they serve, even the service of the tabernacle of the congregation."'),
('Numbers', 18, 'kids', 3, 'What gift did the priests receive that represented the first and best of everything the Israelites produced?', 'The firstfruits and heave offerings — the best of the oil, wine, and grain', 'The last portion of every harvest', 'The middle part of every flock', 'Whatever was left over after everyone else ate', 'a', 'Numbers 18:12 — "All the best of the oil, and all the best of the wine, and of the wheat, the firstfruits of them which they shall offer unto the LORD, them have I given thee."'),
-- Teens
('Numbers', 18, 'teens', 1, 'What serious warning did God give about unauthorized persons approaching the tabernacle?', 'The stranger that cometh nigh shall be put to death', 'They would be exiled from Israel', 'They would be made servants of the priests', 'They would lose their tribal inheritance', 'a', 'Numbers 18:7 — "The stranger that cometh nigh shall be put to death."'),
('Numbers', 18, 'teens', 2, 'What was the priests'' specific responsibility described in Numbers 18:1 regarding the sanctuary?', 'They were to bear the iniquity of the sanctuary — personally responsible for any offenses connected to the priestly office', 'They were to clean the tabernacle furniture', 'They were to guard the ark at all times', 'They were to teach the law to the people', 'a', 'Numbers 18:1 — "And the LORD said unto Aaron, Thou and thy sons and thy father''s house with thee shall bear the iniquity of the sanctuary: and thou and thy sons with thee shall bear the iniquity of your priesthood."'),
('Numbers', 18, 'teens', 3, 'What portion of the tithes they received were the Levites commanded to give to the priests?', 'A tenth of the tenth — a tithe of the tithe — the best portion', 'Half of all they received', 'A third of all they received', 'Nothing — they kept all they received', 'a', 'Numbers 18:26 — "When ye take of the children of Israel the tithes which I have given you from them for your inheritance, then ye shall offer up an heave offering of it for the LORD, even a tenth part of the tithe."'),
('Numbers', 18, 'teens', 4, 'What was the redemption price for a firstborn son according to Numbers 18?', 'Five shekels of silver, after a month old', 'Ten shekels of gold', 'A lamb without blemish', 'One-tenth of the family''s flock', 'a', 'Numbers 18:16 — "And those that are to be redeemed from a month old shalt thou redeem, according to thine estimation, for the money of five shekels."'),
('Numbers', 18, 'teens', 5, 'What distinction did God make between firstborn clean animals versus firstborn of men and unclean animals?', 'Firstborn of men and unclean animals must be redeemed with money; firstborn of clean animals (ox, sheep, goat) belong to God and their blood is offered on the altar, the flesh going to the priests', 'All firstborn animals were treated identically', 'Men''s firstborns were sacrificed, animals were redeemed', 'Only the firstborn of Levi belonged to God', 'a', 'Numbers 18:15-17 — "Every thing that openeth the matrix in all flesh... shalt thou redeem... But the firstling of a cow, or the firstling of a sheep, or the firstling of a goat, thou shalt not redeem; they are holy: thou shalt sprinkle their blood upon the altar."'),
-- Adults
('Numbers', 18, 'adults', 1, 'How does "I am thy part and thine inheritance" (Numbers 18:20) function as a theological statement about the nature of ministry?', 'It establishes that true ministry is not compensated with land, power, or worldly security but with God Himself — the minister''s deepest satisfaction and provision is a direct relationship with the divine, which exceeds all earthly inheritance', 'The statement was only about economic arrangements', 'God being the inheritance was a consolation prize', 'All Israelites had God as their inheritance equally', 'a', 'Numbers 18:20 — "I am thy part and thine inheritance." This becomes the model for NT ministry (1 Corinthians 9; 1 Timothy 5:17-18) and the Psalms'' language of God as "my portion" (Psalm 16:5; 73:26; 119:57; 142:5).'),
('Numbers', 18, 'adults', 2, 'How does the "covenant of salt" (Numbers 18:19) function in its ancient Near Eastern context?', 'Salt was a universal symbol of preservation, permanence, and covenant loyalty — a "covenant of salt" was the most unbreakable form of agreement, indicating that the priestly arrangement was an eternal, inviolable covenant with God', 'Salt was used only for food preservation', 'The phrase means the covenant was bitter', 'Salt covenants were specific to Levitical law only', 'a', 'Numbers 18:19 — "It is a covenant of salt for ever before the LORD unto thee and to thy seed with thee." 2 Chronicles 13:5 uses the same phrase for the Davidic covenant: "a covenant of salt."'),
('Numbers', 18, 'adults', 3, 'What is the theological significance of Aaron bearing the "iniquity of the sanctuary" (Numbers 18:1)?', 'The priests are not merely administrators but vicarious bearers of the people''s ritual failures — any lapse in proper worship is laid on the priests, making them a buffer between a holy God and an imperfect people, pointing forward to Christ who bears the iniquity of us all', 'Bearing iniquity was a symbolic phrase with no real weight', 'The iniquity referred only to theft from the sanctuary', 'Only the high priest bore iniquity on the Day of Atonement', 'a', 'Numbers 18:1 — "Thou and thy sons and thy father''s house with thee shall bear the iniquity of the sanctuary." Isaiah 53:11 uses the same verb (nasa'') for the Suffering Servant: "he shall bear their iniquities."'),
('Numbers', 18, 'adults', 4, 'How does the Levites giving a tithe of the tithe (Numbers 18:26-28) model the principle of faithful stewardship among those who serve in ministry?', 'Those who receive support for ministry are not exempt from giving — they too give from what they receive, establishing that the principle of sacrificial stewardship applies to all, including full-time ministers', 'Only laypeople are required to tithe', 'The Levites'' tithe was optional', 'The Levites gave their tithe to the tabernacle treasury', 'a', 'Numbers 18:28 — "Thus ye also shall offer an heave offering unto the LORD of all your tithes, which ye receive of the children of Israel; and ye shall give thereof the LORD''s heave offering to Aaron the priest." The minister both receives and gives.'),
('Numbers', 18, 'adults', 5, 'What does the firstborn redemption system (Numbers 18:15-16) reveal about the theology of redemption in the Mosaic economy?', 'Every firstborn Israelite male belongs to God by right of the exodus (Exodus 13:2) — the five-shekel redemption price acknowledges God''s ownership while providing a substitute payment, establishing the principle that redemption requires a price paid to the rightful owner', 'The firstborn system was only economic regulation', 'Redemption was optional for wealthy families', 'The system applied only to Levites', 'a', 'Exodus 13:2 — "Sanctify unto me all the firstborn... it is mine." Numbers 18:16 — "for the money of five shekels." The theology of paying a price to release what belongs to God by right runs from Exodus through Ruth to Galatians 4:5.'),
('Numbers', 18, 'adults', 6, 'How does Paul''s argument in 1 Corinthians 9:13-14 depend on the principles established in Numbers 18?', 'Paul explicitly grounds the right of gospel ministers to material support in the OT pattern of those who serve the altar partaking of the altar''s offerings — the Levitical precedent is the theological basis for the Christian principle of supporting gospel workers', 'Paul''s arguments are entirely independent of the OT', 'Paul contradicts the Numbers 18 pattern', 'Only the specific amounts in Numbers 18 are binding', 'a', '1 Corinthians 9:13-14 — "Do ye not know that they which minister about holy things live of the things of the temple... Even so hath the Lord ordained that they which preach the gospel should live of the gospel." Paul draws directly on Numbers 18''s principle.'),
('Numbers', 18, 'adults', 7, 'What is the significance of the "heave offering" (terumah) as distinct from burnt offerings in the Numbers 18 system?', 'The terumah (contribution offering) was specifically set apart and elevated as a portion dedicated to God and then given to the priests — its root taram means to lift up, symbolizing the act of consecrating the best portion upward to God before enjoying the rest', 'Heave offerings and burnt offerings were identical', 'The heave offering was a lesser category of gift', 'The term describes only the physical motion of the priest', 'a', 'Numbers 18:24 — "But the tithes of the children of Israel, which they offer as an heave offering unto the LORD, I have given to the Levites to inherit." The terumah system embedded the theology of consecration into everyday agricultural life.'),
('Numbers', 18, 'adults', 8, 'How does Hebrews 7:5-9 use the Levitical tithe system of Numbers 18 to argue for the superiority of Melchizedek''s priesthood?', 'Hebrews argues that since Abraham (and thus Levi, still in Abraham''s loins) paid tithes to Melchizedek, the Melchizedekan priesthood is superior to the Levitical — the lesser blesses the greater, and the greater receives tithes from the lesser', 'Hebrews ignores the Levitical tithe system', 'The Melchizedek argument is unrelated to Numbers 18', 'Hebrews argues that both priesthoods are equal', 'a', 'Hebrews 7:9 — "And as I may so say, Levi also, who receiveth tithes, payed tithes in Abraham." The same tithe principle that the Levites administered in Numbers 18 becomes the argument for their own subordination to a higher priestly order.');

-- ═══ Numbers Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 19, 'kids', 1, 'What special animal was used to make water for purification from touching a dead body?', 'A red heifer without blemish', 'A white lamb', 'A brown bull', 'A black goat', 'a', 'Numbers 19:2 — "This is the ordinance of the law which the LORD hath commanded... Bring thee a red heifer without spot, wherein is no blemish."'),
('Numbers', 19, 'kids', 2, 'How was a person who had touched a dead body made clean again?', 'They were sprinkled with water mixed with the ashes of the red heifer on the third and seventh days', 'They had to offer a lamb as a sacrifice', 'They washed in the river Jordan', 'They had to fast for seven days', 'a', 'Numbers 19:19 — "And the clean person shall sprinkle upon the unclean on the third day, and on the seventh day: and on the seventh day he shall purify himself, and wash his clothes, and bathe himself in water, and shall be clean at even."'),
('Numbers', 19, 'kids', 3, 'What happened if a person who was unclean from touching a dead body did not purify themselves?', 'They were cut off from Israel because they defiled the tabernacle of the LORD', 'They were made to pay a fine', 'They had to leave Israel forever', 'They became a priest', 'a', 'Numbers 19:20 — "But the man that shall be unclean, and shall not purify himself, that soul shall be cut off from among the congregation, because he hath defiled the sanctuary of the LORD."'),
-- Teens
('Numbers', 19, 'teens', 1, 'What three things were burned together with the red heifer to make the purification ashes?', 'Cedar wood, hyssop, and scarlet thread', 'Salt, oil, and incense', 'Myrrh, frankincense, and cinnamon', 'Wool, linen, and goat hair', 'a', 'Numbers 19:6 — "And the priest shall take cedar wood, and hyssop, and scarlet, and cast it into the midst of the burning of the heifer."'),
('Numbers', 19, 'teens', 2, 'What happened to the priest who burned the red heifer and the man who gathered the ashes?', 'Both became ceremonially unclean and had to wash their clothes and bathe in water', 'Nothing happened to them — they remained clean', 'They had to offer a special sacrifice', 'They were made holier by the process', 'a', 'Numbers 19:7-8,10 — "Then the priest shall wash his clothes, and he shall bathe his flesh in water... he shall be unclean until the even... And he that gathereth the ashes of the heifer shall wash his clothes, and be unclean until the even."'),
('Numbers', 19, 'teens', 3, 'Where were the ashes of the red heifer stored after they were gathered?', 'In a clean place outside the camp, to be kept for a water of separation — a purification for sin', 'In the ark of the covenant', 'In the tabernacle court', 'In the tent of the high priest', 'a', 'Numbers 19:9 — "And a man that is clean shall gather up the ashes of the heifer, and lay them up without the camp in a clean place, and it shall be kept for the congregation of the children of Israel for a water of separation: it is a purification for sin."'),
('Numbers', 19, 'teens', 4, 'Besides touching a dead body, what other situations caused uncleanness requiring the water of purification?', 'Touching a slain person, a bone of a man, or a grave in an open field', 'Eating unclean food only', 'Only direct contact with a corpse', 'Touching a sick person', 'a', 'Numbers 19:16 — "And whosoever toucheth one that is slain with a sword in the open fields, or a dead body, or a bone of a man, or a grave, shall be unclean seven days."'),
('Numbers', 19, 'teens', 5, 'Why would an entire tent and all its contents become unclean when someone died inside it?', 'Every open vessel and every person in the tent was unclean because death contamination spread through the enclosed space', 'Only the person who died was unclean', 'Only the items the dead person touched were unclean', 'Tents were never unclean from death', 'a', 'Numbers 19:14-15 — "When a man dieth in a tent: all that come into the tent, and all that is in the tent, shall be unclean seven days. And every open vessel, which hath no covering bound upon it, is unclean."'),
-- Adults
('Numbers', 19, 'adults', 1, 'How does Hebrews 9:13-14 interpret the red heifer ritual typologically in relation to Christ''s blood?', 'Hebrews contrasts the red heifer ashes which sanctify the flesh (ceremonial purity) with Christ''s blood which purges the conscience from dead works — the physical cleansing is the type, the spiritual cleansing of the conscience is the antitype', 'Hebrews ignores the red heifer entirely', 'The red heifer is a type of the Holy Spirit, not Christ', 'Hebrews uses the red heifer to argue against animal sacrifice', 'a', 'Hebrews 9:13-14 — "For if the blood of bulls and of goats, and the ashes of an heifer sprinkling the unclean, sanctifieth to the purifying of the flesh: How much more shall the blood of Christ, who through the eternal Spirit offered himself without spot to God, purge your conscience from dead works."'),
('Numbers', 19, 'adults', 2, 'What is the theological paradox at the heart of the red heifer ordinance — that it makes the unclean clean while making the clean unclean?', 'This paradox prefigures substitutionary atonement: Christ became sin for us (2 Corinthians 5:21) — He who was holy became contaminated with our uncleanness to make us clean, as seen in the priest and ash-gatherer becoming unclean through the purification process', 'The paradox shows the law''s arbitrary nature', 'The clean becoming unclean was an unintended consequence', 'Both outcomes were purely ceremonial with no deeper meaning', 'a', '2 Corinthians 5:21 — "For he hath made him to be sin for us, who knew no sin; that we might be made the righteousness of God in him." The red heifer''s paradox — purity transferred at cost to the pure one — directly models Christ''s substitution.'),
('Numbers', 19, 'adults', 3, 'What does the requirement that the red heifer be "without spot" and "never yoked" (Numbers 19:2) contribute typologically?', 'The heifer''s unblemished perfection and complete freedom from human labor represents the sinlessness and sovereign freedom of Christ who was "without blemish" (1 Peter 1:19) and whose life was given freely, not under compulsion', 'The requirements were only practical agricultural criteria', 'The yoke requirement related to farming economics', 'Any healthy animal would have served the same purpose', 'a', '1 Peter 1:19 — "But with the precious blood of Christ, as of a lamb without blemish and without spot." The never-yoked requirement echoes the principle that the sacrificial animal must be entirely set apart for sacred use.'),
('Numbers', 19, 'adults', 4, 'Why is the red heifer classified as a "chukkat" (statute) — a law without a clear rational explanation — rather than a "mishpat" (judgment)?', 'The sages identified chukkot as divine decrees that exceed human reason — they are to be obeyed by faith in God''s authority rather than by logical deduction, teaching that some aspects of holiness and atonement transcend human comprehension and require pure obedience', 'The classification was editorial and unimportant', 'Numbers 19 gives a full rational explanation for the law', 'Chukkot were considered less binding than mishpatim', 'a', 'Numbers 19:2 — "This is the ordinance (chukkat) of the law." The Talmud (Yoma 67b) identifies the red heifer as the paradigmatic chok — a decree obeyed because God commanded it, not because it is understood.'),
('Numbers', 19, 'adults', 5, 'How do the elements burned with the heifer — cedar, hyssop, and scarlet thread — connect to other significant purification rituals in the Torah?', 'These same three items appear in the cleansing of leprosy (Leviticus 14:4-6) and the dedication of a house (Leviticus 14:49-52) — suggesting a unified theology of purification from death-related contamination throughout the Mosaic system', 'The three items were chosen randomly', 'Cedar, hyssop, and scarlet appear only in Numbers 19', 'The items had individual meanings only, not a combined symbolism', 'a', 'Leviticus 14:4 — "Then shall the priest command to take for him that is to be cleansed two birds alive and clean, and cedar wood, and scarlet, and hyssop." The triplet forms a consistent purification formula, and hyssop appears in the Passover (Exodus 12:22) and David''s cleansing prayer (Psalm 51:7).'),
('Numbers', 19, 'adults', 6, 'What does the location of the heifer''s burning outside the camp (Numbers 19:3) contribute to its typological significance?', 'Christ was crucified "without the gate" (Hebrews 13:12-13) — outside the city — directly fulfilling the pattern of the red heifer slaughtered outside the camp; Hebrews explicitly draws this connection as a basis for Christians to go "outside the camp" bearing His reproach', 'The location was only a practical waste disposal arrangement', 'The location signifies the heifer''s unworthiness', 'Hebrews 13 does not reference the Numbers 19 pattern', 'a', 'Hebrews 13:11-13 — "For the bodies of those beasts... are burned without the camp. Wherefore Jesus also, that he might sanctify the people with his own blood, suffered without the gate."'),
('Numbers', 19, 'adults', 7, 'What sociological and communal function did the water of purification serve in maintaining the holiness of the Israelite community?', 'It provided a practical mechanism for managing the near-universal experience of death-related uncleanness — without it, the entire assembly could become collectively unfit to approach the tabernacle, showing that God provided a means of restoration for unavoidable contamination', 'The ritual was only for extreme cases of sin', 'Most Israelites never needed the purification water', 'The ritual applied only to priests', 'a', 'Numbers 19:9 — "it shall be kept for the congregation of the children of Israel for a water of separation: it is a purification for sin." Every family touched by death needed access to this cleansing — God built restoration into the structure of community life.'),
('Numbers', 19, 'adults', 8, 'How does the "running water" (living water) required for the purification mixture (Numbers 19:17) connect to broader biblical imagery of cleansing and life?', 'Living water (mayim chayyim — flowing, spring-fed water) is consistently associated with divine life and cleansing throughout Scripture — from Levitical purification to Ezekiel''s river to John 4:10 where Jesus offers "living water" as the ultimate purification', 'Running water was chosen for practical hygienic reasons only', 'The type of water was irrelevant to the ritual', 'Living water imagery is only a New Testament concept', 'a', 'Numbers 19:17 — "And for an unclean person they shall take of the ashes of the burnt heifer of purification for sin, and running water shall be put thereto in a vessel." John 4:10 — "If thou knewest the gift of God... he would have given thee living water."');

-- ═══ Numbers Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 20, 'kids', 1, 'What happened to Miriam in Numbers chapter 20?', 'She died and was buried at Kadesh', 'She was healed of her leprosy again', 'She became a prophetess for the Gentiles', 'She led the women in singing', 'a', 'Numbers 20:1 — "And Miriam died there, and was buried there."'),
('Numbers', 20, 'kids', 2, 'What did God tell Moses to do to get water for the people when they complained about having no water?', 'Speak to the rock before their eyes', 'Strike the rock with his rod', 'Dig in the ground', 'Pour water from a jar onto the sand', 'a', 'Numbers 20:8 — "Take the rod, and gather thou the assembly together, thou, and Aaron thy brother, and speak ye unto the rock before their eyes; and it shall give forth his water."'),
('Numbers', 20, 'kids', 3, 'Where did Aaron die at the end of Numbers chapter 20?', 'On mount Hor', 'In the wilderness of Paran', 'At Kadesh-barnea', 'By the Jordan River', 'a', 'Numbers 20:27-28 — "And they went up into mount Hor in the sight of all the congregation. And Moses stripped Aaron of his garments, and put them upon Eleazar his son; and Aaron died there in the top of the mount."'),
-- Teens
('Numbers', 20, 'teens', 1, 'What did Moses do wrong when he brought water from the rock, and what was his punishment?', 'He struck the rock twice instead of speaking to it; he and Aaron were told they would not bring the congregation into the promised land', 'He prayed the wrong prayer at the rock', 'He struck the rock only once', 'He asked for water without telling the people', 'a', 'Numbers 20:11-12 — "And Moses lifted up his hand, and with his rod he smote the rock twice: and the water came out abundantly... And the LORD spake unto Moses and Aaron, Because ye believed me not, to sanctify me in the eyes of the children of Israel, therefore ye shall not bring this congregation into the land."'),
('Numbers', 20, 'teens', 2, 'What name did Moses give to the place where Israel quarreled over water?', 'Meribah, meaning strife or contention', 'Massah, meaning testing', 'Taberah, meaning burning', 'Kibroth, meaning graves', 'a', 'Numbers 20:13 — "This is the water of Meribah; because the children of Israel strove with the LORD, and he was sanctified in them."'),
('Numbers', 20, 'teens', 3, 'What route did Israel ask the king of Edom for permission to travel, and what did they promise?', 'They asked to pass through Edom by the king''s highway, promising to stay on the road and pay for any water they drank', 'They asked to travel through Edom''s cities', 'They asked Edom for an army escort', 'They asked to settle in Edom temporarily', 'a', 'Numbers 20:17 — "Let us pass, I pray thee, through thy country: we will not pass through the fields, or through the vineyards, neither will we drink of the water of the wells: we will go by the king''s high way, we will not turn to the right hand nor to the left."'),
('Numbers', 20, 'teens', 4, 'How did the king of Edom respond to Israel''s request for passage?', 'He refused and came out with a strong army to block them — so Israel turned away', 'He welcomed Israel and gave them food', 'He asked Moses to pay a toll', 'He asked Pharaoh for advice first', 'a', 'Numbers 20:20-21 — "And Edom said, Thou shalt not pass by me, lest I come out against thee with the sword... And Edom refused to give Israel passage through his border: wherefore Israel turned away from him."'),
('Numbers', 20, 'teens', 5, 'How was Aaron''s death handled — who succeeded him and what happened to his priestly garments?', 'Moses stripped Aaron''s garments and placed them on his son Eleazar on mount Hor — Eleazar became high priest in his father''s place', 'Aaron''s garments were buried with him', 'Eleazar was installed by a ceremony at the tabernacle', 'Joshua succeeded Aaron as high priest', 'a', 'Numbers 20:28 — "And Moses stripped Aaron of his garments, and put them upon Eleazar his son; and Aaron died there in the top of the mount."'),
-- Adults
('Numbers', 20, 'adults', 1, 'How does 1 Corinthians 10:4 interpret the rock at Meribah, and what does Moses striking rather than speaking to it signify typologically?', 'Paul identifies the rock as Christ ("that Rock was Christ"); striking it the first time (Exodus 17) typified the crucifixion — Christ smitten once for all. Striking the second time violated the type: Christ is not to be struck again but spoken to in prayer, and Moses'' disobedience broke the typological pattern', 'The rock is simply a historical reference in 1 Corinthians', 'Both the first and second striking were typologically identical', 'Paul uses the rock to argue against water baptism', 'a', '1 Corinthians 10:4 — "And did all drink the same spiritual drink: for they drank of that spiritual Rock that followed them: and that Rock was Christ." The first striking (Exodus 17:6) pictures the crucifixion; speaking to it thereafter pictures prayer to the risen Christ — striking again contradicts resurrection theology.'),
('Numbers', 20, 'adults', 2, 'What does "ye believed me not, to sanctify me in the eyes of the children of Israel" (Numbers 20:12) reveal about the precise nature of Moses'' sin?', 'The failure was a lack of trust in God''s word — God said speak, Moses struck — and the result was a failure to display God''s character accurately before the people; it was a misrepresentation of God, not merely a procedural error', 'Moses'' sin was simply losing his temper', 'The sin was only about following the correct ritual', 'God was more upset about the twice-striking than the anger', 'a', 'Numbers 20:12 — "Because ye believed me not, to sanctify me in the eyes of the children of Israel." The word "sanctify" (qadash — to set apart as holy) indicates the issue: Moses'' action made God appear as one who must be compelled by force rather than responded to in faithful obedience.'),
('Numbers', 20, 'adults', 3, 'How does the severity of Moses'' punishment — exclusion from Canaan — reflect the biblical principle that greater privilege entails greater accountability?', 'Moses was the mediator of the entire covenant, the most intimately acquainted with God''s character of any person alive — his failure to represent God accurately carried greater consequence because those God entrusts with greater revelation are held to a proportionally higher standard', 'The punishment was disproportionately harsh', 'The same punishment would have applied to any Israelite', 'Moses'' previous faithfulness should have cancelled the penalty', 'a', 'Numbers 20:12 and James 3:1 — "My brethren, be not many masters, knowing that we shall receive the greater condemnation." Luke 12:48 — "For unto whomsoever much is given, of him shall be much required."'),
('Numbers', 20, 'adults', 4, 'What is the significance of the deaths of both Miriam and Aaron in Numbers 20, alongside Moses'' disqualification, for the wilderness narrative?', 'All three leaders of the exodus generation — Miriam, Aaron, and Moses — are disqualified or die in this chapter, signalling that the first generation is completely passing away and a new generation under new leadership (Joshua) will inherit the covenant promises', 'Only Aaron''s death is narratively significant', 'Moses'' disqualification was reversed before his death', 'Miriam''s death is unrelated to the larger narrative', 'a', 'Numbers 20:1 (Miriam dies), 20:12 (Moses and Aaron barred), 20:28 (Aaron''s death) — together these three events close the chapter on the exodus generation. Deuteronomy 34:5 and 32:48-52 complete the pattern with Moses'' own death.'),
('Numbers', 20, 'adults', 5, 'How does Edom''s refusal of passage illustrate the broken covenant relationship between the descendants of Jacob and Esau?', 'Moses appeals to Edom as "thy brother Israel" (v.14), invoking the Jacob-Esau relationship — but Edom''s refusal and military threat show that the sibling rivalry begun in Genesis 25 has hardened into national enmity, which later prophets (Obadiah, Ezekiel 35) condemn severely', 'Edom''s refusal was politically reasonable with no deeper significance', 'The Jacob-Esau reference is rhetorical with no actual treaty claim', 'Edom had no obligation to Israel', 'a', 'Numbers 20:14 — "And Moses sent messengers from Kadesh unto the king of Edom, Thus saith thy brother Israel..." Obadiah 10-12 later condemns Edom for standing against "thy brother Jacob." The fraternal language makes the refusal a covenantal betrayal.'),
('Numbers', 20, 'adults', 6, 'What is the theological meaning of the high priestly garments being transferred from Aaron to Eleazar before Aaron dies, rather than after?', 'The transfer ensures no gap in the priestly ministry — the tabernacle is never without a high priest because the garments (the sacred office) pass from the dying priest to the living successor while Aaron is still alive, modeling continuity of mediation', 'The transfer was simply a practical expedient', 'The order of transfer was arbitrary', 'Aaron could have officiated in plain clothes after the transfer', 'a', 'Numbers 20:28 — "Moses stripped Aaron of his garments, and put them upon Eleazar his son; and Aaron died there." This transfer-before-death pattern demonstrates the indispensability of ongoing priestly mediation — a pattern fulfilled in Christ whose priesthood is eternal and knows no succession gap (Hebrews 7:24).'),
('Numbers', 20, 'adults', 7, 'How does Psalm 106:32-33 interpret the sin at Meribah, and what additional detail does it provide beyond Numbers 20?', 'Psalm 106 states they "angered him also at the waters of strife, so that it went ill with Moses for their sakes: Because they provoked his spirit, so that he spake unadvisedly with his lips" — adding that the people''s provocation contributed to Moses'' rash words, while still holding Moses responsible', 'Psalm 106 exonerates Moses entirely', 'The psalm blames only the people, not Moses', 'Psalm 106 never references Meribah', 'a', 'Psalm 106:32-33 — "They angered him also at the waters of strife, so that it went ill with Moses for their sakes: Because they provoked his spirit, so that he spake unadvisedly with his lips." The psalm adds the detail of Moses'' rash speech, consistent with the anger evident in Numbers 20:10.'),
('Numbers', 20, 'adults', 8, 'How does Numbers 20 function as a theological hinge point between the first and second generation of Israel?', 'The chapter opens with the last surviving first-generation leader (Miriam) dying, records Moses'' disqualification and Aaron''s death, and closes with Eleazar elevated as high priest — it is the death of the old guard and the transition to the Joshua generation that will actually enter the land', 'Numbers 20 is a collection of unrelated events', 'The generational transition happens in Numbers 21 rather than 20', 'Moses remains the primary leader until Joshua 1', 'a', 'Numbers 20:1 (Miriam dies), 20:12 (Moses and Aaron barred), 20:28 (Aaron dies, Eleazar installed) — the entire chapter is structured as a transition passage. Joshua 1:1-2 immediately follows Moses'' death in Deuteronomy 34, confirming the generational change as the arc of the final wilderness chapters.');
